function maxSubarray(nums) {
  // Kadane's algorithm.
  // Walk left-to-right. Track:
  //   currentBest = the max sum of a subarray ENDING at index i
  //   globalBest  = the answer so far
  // At each step: currentBest = max(nums[i], currentBest + nums[i])
  //               (start fresh from i, OR extend the previous run)
}

solution:
// O(n) time, O(1) space.
// Kadane's insight: the best subarray ending at i is either {nums[i]} alone,
// or {best ending at i-1} + nums[i]. Take whichever is larger.
function maxSubarray(nums) {
  let currentBest = nums[0];
  let globalBest  = nums[0];
  for (let i = 1; i < nums.length; i++) {
    currentBest = Math.max(nums[i], currentBest + nums[i]);
    globalBest  = Math.max(globalBest, currentBest);
  }
  return globalBest;
}
